var client2;
var initMcp = async () => {
  client2 = new MultiServerMCPClient({
    filesystem: {
      transport: "stdio",
      command: "npx",
      args: ["-y", "@modelcontextprotocol/server-filesystem", "."]
    },
    fetch: {
      "command": "npx",
      "args": [
        "-y",
        "@tokenizin/mcp-npx-fetch"
      ]
    }
  });
  await client2.initializeConnections();
  const tools2 = await client2.getTools();
  console.log(tools2, "tools");
  console.log(tools2.map((t) => t.name));
  return tools2;
};
var allTools = async () => {
  if (!client2) {
    console.error("MCP\u5BA2\u6237\u7AEF\u672A\u521D\u59CB\u5316");
    return [];
  }
  try {
    const tools2 = await client2.getTools();
    return tools2;
  } catch (error48) {
    console.error("\u83B7\u53D6MCP\u5DE5\u5177\u5217\u8868\u5931\u8D25:", error48);
    return [];
  }
};

// src/modules/index.ts
var modelName = "GLM";
var currentModel = getModelByName(modelName);
var agent;
var initAgent = async () => {
  if (!currentModel) {
    throw new Error(`\u521D\u59CB\u5316Agent\u5931\u8D25\uFF1A\u6A21\u578B ${modelName} \u672A\u627E\u5230\u6216\u521D\u59CB\u5316\u5931\u8D25`);
  }
  await initMcp();
  let tools2 = await allTools();
  agent = createAgent({
    model: currentModel,
    tools: tools2
  });
  console.log(agent, "agent");
};
initAgent();
var getModels = () => {
  const models = [];
  const modelEntries = Array.isArray(deepSeekmodels) ? deepSeekmodels.entries() : Object.entries(deepSeekmodels);
  for (const [_, modelInstance] of modelEntries) {
    if (!modelInstance?.model) continue;
    const isDeepSeekModel = modelInstance.model === "deepseek-chat" || modelInstance.model === "deepseek-reasoner";
    models.push({
      name: modelInstance.model,
      label: isDeepSeekModel ? "deepseek" : modelInstance.model
    });
  }
  return models;
};
var switchModel = (newModelName) => {
  try {
    const newModel = getModelByName(newModelName);
    if (!newModel) {
      throw new Error(`\u6A21\u578B ${newModelName} \u4E0D\u5B58\u5728`);
    }
    currentModel = newModel;
    initAgent();
    console.log(`\u2705 \u6210\u529F\u5207\u6362\u5230\u6A21\u578B\uFF1A${newModelName}`);
    return newModel;
  } catch (error48) {
    console.error(`\u274C \u5207\u6362\u6A21\u578B\u5931\u8D25\uFF1A${error48.message}`);
    throw error48;
  }
};
var getAgent = () => {
  if (!agent) {
    throw new Error("Agent\u672A\u521D\u59CB\u5316\uFF0C\u8BF7\u68C0\u67E5\u6A21\u578B\u914D\u7F6E");
  }
  return agent;
};

// src/chat/index.ts
var Agent = class {
  async request(userMessage) {
    console.log(getAgent(), "\u8BD5\u8BD5\u8FD9\u4E2Aagent");
    let agent2 = getAgent();
    const result = await agent2.invoke({
      messages: [{ role: "user", content: userMessage }]
    });
    return this.response(result);
  }
  response(result) {
    console.log("\u54CD\u5E94\u5904\u7406", result);
    const lastMessage = result.messages.at(-1);
    return lastMessage.content;
  }
};

