var IDEFROMWEBVIEWREQ = {
  WEBVIEW_READY: "webview-ready",
  CHAT_REQUEST: "chat-request",
  CHANGE_MODEL_REQUEST: "change-model-request"
};

// src/pluginscore/chatui/chatuiprovider.ts
var ChatUiProvider = class {
  _view;
  _context;
  _agent;
  constructor(context2) {
    this._context = context2;
    this._agent = new Agent();
  }
  resolveWebviewView(webviewView) {
    this._view = webviewView;
    webviewView.webview.options = {
      enableScripts: true,
      localResourceRoots: [this._context.extensionUri]
    };
    webviewView.webview.html = this.dev();
    webviewView.webview.onDidReceiveMessage(async (message) => {
      const { command, data } = message;
      const config2 = {
        [IDEFROMWEBVIEWREQ.WEBVIEW_READY]: (message2) => this.handleInit(message2),
        [IDEFROMWEBVIEWREQ.CHAT_REQUEST]: (message2) => this.handleChatRequest(message2),
        [IDEFROMWEBVIEWREQ.CHANGE_MODEL_REQUEST]: (message2) => this.handleChangeModel(message2)
      };
      config2[command]?.(message);
    });
  }
  /**
   * webview初始化ide发送给webview的config数据
   * @param message
   */
  async handleInit(message) {
    this.sendMessageToWebView({
      command: "config-response",
      data: {
        currentModel: currentModel.model,
        modelList: getModels()
      }
    });
  }
  async handleChatRequest(message) {
    let aiResponseContent = await this._agent.request(message.data.userMessage);
    this.sendMessageToWebView({
      command: "chat-response",
      data: {
        content: aiResponseContent,
        model: currentModel.model
      }
    });
  }
  async handleChangeModel(message) {
    console.log(message.data.model, "message.data.model;");
    switch (message.data.model) {
      case "deepseek-chat":
        switchModel("deepseekChat");
        break;
      case "deepseek-reasoner":
        switchModel("deepseekReasoner");
        break;
      default:
        break;
    }
  }
  sendMessageToWebView(message) {
    this._view?.webview.postMessage(message);
  }
  // 开发环境自动热更新
  dev() {
    let devUrl = "http://localhost:5180";
    let wsurl = "//localhost:5180";
    return `
      <!DOCTYPE html>
      <html lang="en">
        <head>
          <meta charset="UTF-8" />
          <meta name="viewport" content="width=device-width, initial-scale=1.0">
          <meta http-equiv="Content-Security-Policy" content="
            default-src 'none';
            style-src ${devUrl} 'unsafe-inline' 'unsafe-eval';
            script-src ${devUrl} 'unsafe-eval' 'unsafe-inline';
            connect-src ws:${wsurl} ${devUrl} vscode-webview:;
            font-src ${devUrl};
          " />
          <title>vscode plugin demo</title>
        </head>
        <body>
          <div id="app"></div>
          <script type="module" src="${devUrl}/src/main.ts"></script>
        </body>
      </html>
    `;
  }
  getHtml(scriptUri, styleUri) {
    return `<!DOCTYPE html>
      <html lang="en">
      <head>
        <meta charset="UTF-8">
        <meta name="viewport" content="width=device-width, initial-scale=1.0">
        <link href="${styleUri}" crossorigin rel="stylesheet">
        <title>vscode plugin demo</title>
      </head>
      <body>
        <div id="app"></div>
        <script type="module" crossorigin src="${scriptUri}"></script>
      </body>
      </html>`;
  }
};

